import { Test } from '@nestjs/testing';
import { AppModule } from './src/app.module';
import { NotFoundException } from '@nestjs/common';
import * as fs from 'fs';

async function test() {
  try {
    if (!fs.existsSync('./src/courses/courses.controller.ts')) throw new Error('[VALIDATION_ERROR] No has creado el controlador de Courses. Recuerda usar: nest g res courses --no-spec');
    if (!fs.existsSync('./src/courses/courses.service.ts')) throw new Error('[VALIDATION_ERROR] No has creado el servicio de Courses.');
    if (!fs.existsSync('./src/courses/courses.module.ts')) throw new Error('[VALIDATION_ERROR] No has creado el módulo de Courses.');
    if (!fs.existsSync('./src/courses/dto/create-course.dto.ts')) throw new Error('[VALIDATION_ERROR] Falta el DTO de creación: create-course.dto.ts');
    if (!fs.existsSync('./src/courses/dto/update-course.dto.ts')) throw new Error('[VALIDATION_ERROR] Falta el DTO de actualización: update-course.dto.ts');

    const controllerCode = fs.readFileSync('./src/courses/courses.controller.ts', 'utf8');
    if (!controllerCode.includes('ParseIntPipe')) {
      throw new Error('[VALIDATION_ERROR] Debes usar ParseIntPipe en el controlador para transformar y validar los parámetros "id" a tipo number.');
    }
    const matches = controllerCode.match(/ParseIntPipe/g) || [];
    if (matches.length < 3) {
      throw new Error('[VALIDATION_ERROR] Asegúrate de aplicar ParseIntPipe en los parámetros de ruta ":id" en findOne, update y remove.');
    }

    const { CoursesController } = await import('./src/courses/courses.controller');
    const { CoursesService } = await import('./src/courses/courses.service');
    const moduleRef = await Test.createTestingModule({ imports: [AppModule] }).compile();

    let controller: any;
    try { 
      controller = moduleRef.get(CoursesController, { strict: false }); 
    } catch(e) { 
      throw new Error('[VALIDATION_ERROR] El CoursesController no está registrado en el modulo.'); 
    }

    let service: any;
    try { 
      service = moduleRef.get(CoursesService, { strict: false }); 
    } catch(e) { 
      throw new Error('[VALIDATION_ERROR] El CoursesService no está registrado en el modulo.'); 
    }

    const initialCourses = await controller.findAll();
    if (!Array.isArray(initialCourses)) {
      throw new Error('[VALIDATION_ERROR] El método findAll() del controlador debe retornar un arreglo.');
    }
    if (initialCourses.length === 0) {
      throw new Error('[VALIDATION_ERROR] Tu base de datos en memoria (arreglo en el servicio) debe inicializarse con al menos un curso.');
    }
    const initialLength = initialCourses.length;

    const firstCourse = initialCourses[0];
    if (typeof firstCourse.id !== 'number') {
      throw new Error('[VALIDATION_ERROR] Cada curso debe tener una propiedad \"id\" numérica.');
    }

    const foundCourse = await controller.findOne(firstCourse.id);
    if (!foundCourse || foundCourse.id !== firstCourse.id) {
      throw new Error(`[VALIDATION_ERROR] El método findOne(${firstCourse.id}) no devolvió el curso correcto.`);
    }

    let findOneThrew = false;
    try {
      await controller.findOne(9999);
    } catch (e: any) {
      if (e instanceof NotFoundException) {
        findOneThrew = true;
      } else {
        throw new Error(`[VALIDATION_ERROR] findOne(9999) debe lanzar un NotFoundException. Se obtuvo: ${e.message}`);
      }
    }
    if (!findOneThrew) {
      throw new Error('[VALIDATION_ERROR] El método findOne(9999) no arrojó una excepción NotFoundException.');
    }

    const newCoursePayload = { name: 'Curso de Testing Avanzado', duration: 12 };
    const createdCourse = await controller.create(newCoursePayload);
    if (!createdCourse || typeof createdCourse.id !== 'number' || createdCourse.name !== newCoursePayload.name) {
      throw new Error('[VALIDATION_ERROR] El método create() no devolvió el curso recién creado.');
    }

    const updatedCourses = await controller.findAll();
    if (updatedCourses.length <= initialLength) {
      throw new Error('[VALIDATION_ERROR] El curso nuevo no se agregó correctamente a tu listado.');
    }

    const updatePayload = { name: 'Curso de NestJS Avanzado Pro', duration: 20 };
    const updatedCourse = await controller.update(createdCourse.id, updatePayload);
    if (!updatedCourse || updatedCourse.name !== updatePayload.name) {
      throw new Error('[VALIDATION_ERROR] El método update() no aplicó ni devolvió los cambios correctamente.');
    }

    let updateThrew = false;
    try {
      await controller.update(9999, updatePayload);
    } catch (e: any) {
      if (e instanceof NotFoundException) {
        updateThrew = true;
      }
    }
    if (!updateThrew) {
      throw new Error('[VALIDATION_ERROR] El método update(9999) debe lanzar un NotFoundException si el curso no existe.');
    }

    const deleteId = createdCourse.id;
    const removedCourse = await controller.remove(deleteId);
    if (!removedCourse) {
      throw new Error('[VALIDATION_ERROR] El método remove() debe retornar el curso eliminado.');
    }

    let getRemovedThrew = false;
    try {
      await controller.findOne(deleteId);
    } catch (e: any) {
      if (e instanceof NotFoundException) {
        getRemovedThrew = true;
      }
    }
    if (!getRemovedThrew) {
      throw new Error('[VALIDATION_ERROR] El curso eliminado aún se puede obtener a través de findOne().');
    }

    let removeThrew = false;
    try {
      await controller.remove(9999);
    } catch (e: any) {
      if (e instanceof NotFoundException) {
        removeThrew = true;
      }
    }
    if (!removeThrew) {
      throw new Error('[VALIDATION_ERROR] El método remove(9999) debe lanzar un NotFoundException si el curso no existe.');
    }

    console.log('Test pasado correctamente');
  } catch (e: any) {
    throw e;
  }
}
test();
